block.text:
These settings are used globally across the Rundeck App.
     <script type="text/javascript">
       $(function() {  

           var loglevel = $('input[id*="/rundeck/rundecksetup/rundeck/log_level_id"]').val()  

           $('input[id*="/rundeck/rundecksetup/rundeck/log_level_id"]').replaceWith('<select name="/rundeck/rundecksetup/rundeck/log_level" id="/rundeck/rundecksetup/rundeck/log_level_id"><option value="NOTSET">NOTSET</option><option value="DEBUG">DEBUG</option><option value="INFO">INFO</option><option value="WARNING">WARNING</option><option value="ERROR">ERROR</option><option value="CRITICAL">CRITICAL</option></select>')
           $('select[id*="/rundeck/rundecksetup/rundeck/log_level_id"]').val(loglevel) 

           var indexSelect = '<input name="/rundeck/rundecksetup/rundeck/index" id="/rundeck/rundecksetup/rundeck/index_id" list="index_list"/><datalist id="index_list">'

           var indexString = $('input[id*="/rundeck/rundecksetup/rundeck/index_id"]').val()

           var indexStringItems = indexString.split(',');

           for(var i = 0; i < indexStringItems.length; i++) {

               if (i == 0){
                 currentIndex = indexStringItems[i]
               } 

               indexSelect += "<option value=\""+indexStringItems[i]+"\">"+indexStringItems[i]+"</option>"

           }

           indexSelect += "</datalist>"

           $('input[id*="/rundeck/rundecksetup/rundeck/index_id"]').replaceWith(indexSelect)

           $('select[id*="/rundeck/rundecksetup/rundeck/log_level_id"]').val(loglevel) 

           $('input[id*="/rundeck/rundecksetup/rundeck/auth_token_id"]').prop("type","password")
           $('input[id*="/rundeck/rundecksetup/rundeck/index_id"]').val(currentIndex)

        });
     </script>
